--
-- Name: check_entry_move_no_instructor_conflict(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "check_entry_move_no_instructor_conflict"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    conflict_name TEXT;
BEGIN
    -- ถ้าไม่ได้ย้าย day/period และ is_active ไม่เปลี่ยนจาก false→true → ข้าม
    IF OLD.day_of_week = NEW.day_of_week
       AND OLD.period_id = NEW.period_id
       AND (OLD.is_active IS NOT DISTINCT FROM NEW.is_active OR NOT NEW.is_active)
    THEN
        RETURN NEW;
    END IF;

    IF NOT NEW.is_active THEN
        RETURN NEW;
    END IF;

    -- หาครูใน team ของ entry นี้ที่ติดคาบใหม่
    SELECT concat(u.first_name, ' ', u.last_name)
      INTO conflict_name
    FROM timetable_entry_instructors tei_self
    JOIN users u ON u.id = tei_self.instructor_id
    WHERE tei_self.entry_id = NEW.id
      AND EXISTS (
          SELECT 1 FROM timetable_entry_instructors tei_other
          JOIN academic_timetable_entries te_other ON te_other.id = tei_other.entry_id
          WHERE tei_other.instructor_id = tei_self.instructor_id
            AND te_other.day_of_week = NEW.day_of_week
            AND te_other.period_id = NEW.period_id
            AND te_other.id <> NEW.id
            AND te_other.is_active = true
      )
    LIMIT 1;

    IF conflict_name IS NOT NULL THEN
        RAISE EXCEPTION 'ไม่สามารถย้าย — ครู % จะติดคาบ', conflict_name
            USING ERRCODE = 'check_violation';
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION "check_entry_move_no_instructor_conflict"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "check_entry_move_no_instructor_conflict"() IS 'BEFORE UPDATE day/period/is_active บน timetable entries: ถ้าย้ายไปคาบที่ทีมติด → reject';


--
-- Name: check_instructor_no_double_book(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "check_instructor_no_double_book"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    e_day VARCHAR(10);
    e_period UUID;
    e_active BOOLEAN;
    e_slot UUID;
    e_batch UUID;
    conflict_name TEXT;
BEGIN
    SELECT day_of_week, period_id, is_active, activity_slot_id, batch_id
      INTO e_day, e_period, e_active, e_slot, e_batch
    FROM academic_timetable_entries
    WHERE id = NEW.entry_id;

    IF e_day IS NULL OR NOT e_active THEN
        RETURN NEW;
    END IF;

    SELECT concat(u.first_name, ' ', u.last_name)
      INTO conflict_name
    FROM timetable_entry_instructors tei
    JOIN academic_timetable_entries te ON te.id = tei.entry_id
    JOIN users u ON u.id = tei.instructor_id
    WHERE tei.instructor_id = NEW.instructor_id
      AND te.day_of_week = e_day
      AND te.period_id = e_period
      AND te.id <> NEW.entry_id
      AND te.is_active = true
      -- ไม่ใช่ conflict ถ้า entry ตัวที่ชน อยู่ใน slot/batch เดียวกับ NEW
      -- (กลุ่มเดียวกัน — ครูคุมกิจกรรมพร้อมกันหลายห้องได้)
      AND NOT (e_slot IS NOT NULL AND te.activity_slot_id = e_slot)
      AND NOT (e_batch IS NOT NULL AND te.batch_id = e_batch)
    LIMIT 1;

    IF conflict_name IS NOT NULL THEN
        RAISE EXCEPTION 'ครู % มีสอนในคาบนี้อยู่แล้ว (instructor double-book)', conflict_name
            USING ERRCODE = 'check_violation';
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION "check_instructor_no_double_book"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "check_instructor_no_double_book"() IS 'BEFORE INSERT/UPDATE บน timetable_entry_instructors: ป้องกัน race condition จาก multi-admin';


--
-- Name: generate_storage_path(character varying, character varying, "uuid", character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "generate_storage_path"("p_school_id" character varying, "p_file_type" character varying, "p_user_id" "uuid", "p_extension" character varying) RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_path TEXT;
    v_uuid TEXT;
BEGIN
    v_uuid := gen_random_uuid()::TEXT;

    -- Generate path based on file type
    CASE p_file_type
        WHEN 'profile_image' THEN
            v_path := format('school-%s/users/profiles/%s%s',
                p_school_id, v_uuid, p_extension);
        WHEN 'document', 'transcript', 'certificate' THEN
            v_path := format('school-%s/users/documents/%s/%s%s',
                p_school_id, p_user_id, v_uuid, p_extension);
        WHEN 'course_material', 'assignment' THEN
            v_path := format('school-%s/courses/%s%s',
                p_school_id, v_uuid, p_extension);
        WHEN 'school_logo', 'school_banner' THEN
            v_path := format('school-%s/branding/%s%s',
                p_school_id, v_uuid, p_extension);
        ELSE
            v_path := format('school-%s/files/%s%s',
                p_school_id, v_uuid, p_extension);
    END CASE;

    RETURN v_path;
END;
$$;


--
-- Name: refresh_course_primary_instructor("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "refresh_course_primary_instructor"("p_course_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    UPDATE classroom_courses
    SET primary_instructor_id = (
        SELECT instructor_id
        FROM classroom_course_instructors
        WHERE classroom_course_id = p_course_id
        ORDER BY (role = 'primary') DESC, created_at ASC
        LIMIT 1
    )
    WHERE id = p_course_id;
END;
$$;


--
-- Name: FUNCTION "refresh_course_primary_instructor"("p_course_id" "uuid"); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "refresh_course_primary_instructor"("p_course_id" "uuid") IS 'Recompute classroom_courses.primary_instructor_id from junction';


--
-- Name: refresh_subject_default_instructor("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "refresh_subject_default_instructor"("p_subject_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    UPDATE subjects
    SET default_instructor_id = (
        SELECT instructor_id
        FROM subject_default_instructors
        WHERE subject_id = p_subject_id
        ORDER BY (role = 'primary') DESC, created_at ASC
        LIMIT 1
    )
    WHERE id = p_subject_id;
END;
$$;


--
-- Name: FUNCTION "refresh_subject_default_instructor"("p_subject_id" "uuid"); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "refresh_subject_default_instructor"("p_subject_id" "uuid") IS 'Recompute subjects.default_instructor_id from junction';


--
-- Name: trg_asc_cascade_assignments(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_asc_cascade_assignments"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    DELETE FROM activity_slot_classroom_assignments
    WHERE slot_id = OLD.slot_id AND classroom_id = OLD.classroom_id;
    RETURN OLD;
END;
$$;


--
-- Name: FUNCTION "trg_asc_cascade_assignments"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_asc_cascade_assignments"() IS 'ลบห้องจาก participation junction → ลบครูที่ผูกกับห้องนั้น (independent mode)';


--
-- Name: trg_asc_cleanup_empty_slot(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_asc_cleanup_empty_slot"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM activity_slot_classrooms WHERE slot_id = OLD.slot_id
    ) THEN
        DELETE FROM activity_slots WHERE id = OLD.slot_id;
    END IF;
    RETURN OLD;
END;
$$;


--
-- Name: FUNCTION "trg_asc_cleanup_empty_slot"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_asc_cleanup_empty_slot"() IS 'ลบ junction row สุดท้ายของ slot → ลบ slot (cascade ลบ groups, members, timetable entries, etc.)';


--
-- Name: trg_cc_sync_junction(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_cc_sync_junction"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    -- Only act if primary_instructor_id actually changed to a non-null value
    IF NEW.primary_instructor_id IS NOT NULL
       AND (TG_OP = 'INSERT' OR NEW.primary_instructor_id IS DISTINCT FROM OLD.primary_instructor_id)
    THEN
        -- Upsert the new primary, demote others in one statement
        -- Use a function-scoped session variable to avoid re-entering the cci trigger's demote loop
        INSERT INTO classroom_course_instructors (classroom_course_id, instructor_id, role)
        VALUES (NEW.id, NEW.primary_instructor_id, 'primary')
        ON CONFLICT (classroom_course_id, instructor_id)
        DO UPDATE SET role = 'primary';
        -- (The cci trigger will demote any pre-existing primary)
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION "trg_cc_sync_junction"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_cc_sync_junction"() IS 'When primary_instructor_id is written directly, mirror into junction';


--
-- Name: trg_cci_sync_primary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_cci_sync_primary"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        PERFORM refresh_course_primary_instructor(OLD.classroom_course_id);
        RETURN OLD;
    ELSE
        -- INSERT or UPDATE: if role is 'primary', demote other primaries first
        IF NEW.role = 'primary' THEN
            UPDATE classroom_course_instructors
            SET role = 'secondary'
            WHERE classroom_course_id = NEW.classroom_course_id
              AND instructor_id <> NEW.instructor_id
              AND role = 'primary';
        END IF;
        PERFORM refresh_course_primary_instructor(NEW.classroom_course_id);
        RETURN NEW;
    END IF;
END;
$$;


--
-- Name: FUNCTION "trg_cci_sync_primary"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_cci_sync_primary"() IS 'Keep classroom_courses.primary_instructor_id in sync with junction mutations';


--
-- Name: trg_sdi_sync_primary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_sdi_sync_primary"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        PERFORM refresh_subject_default_instructor(OLD.subject_id);
        RETURN OLD;
    ELSE
        IF NEW.role = 'primary' THEN
            UPDATE subject_default_instructors
            SET role = 'secondary'
            WHERE subject_id = NEW.subject_id
              AND instructor_id <> NEW.instructor_id
              AND role = 'primary';
        END IF;
        PERFORM refresh_subject_default_instructor(NEW.subject_id);
        RETURN NEW;
    END IF;
END;
$$;


--
-- Name: FUNCTION "trg_sdi_sync_primary"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_sdi_sync_primary"() IS 'Keep subjects.default_instructor_id in sync with junction mutations';


--
-- Name: trg_subject_sync_junction(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "trg_subject_sync_junction"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    IF NEW.default_instructor_id IS NOT NULL
       AND (TG_OP = 'INSERT' OR NEW.default_instructor_id IS DISTINCT FROM OLD.default_instructor_id)
    THEN
        INSERT INTO subject_default_instructors (subject_id, instructor_id, role)
        VALUES (NEW.id, NEW.default_instructor_id, 'primary')
        ON CONFLICT (subject_id, instructor_id)
        DO UPDATE SET role = 'primary';
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION "trg_subject_sync_junction"(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION "trg_subject_sync_junction"() IS 'When default_instructor_id is written directly, mirror into junction';


