--
-- Name: validate_allowed_days("jsonb"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "validate_allowed_days"("days" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
    day TEXT;
    valid_days TEXT[] := ARRAY['MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT', 'SUN'];
BEGIN
    IF days IS NULL THEN
        RETURN TRUE;
    END IF;

    FOR day IN SELECT jsonb_array_elements_text(days)
    LOOP
        IF NOT (day = ANY(valid_days)) THEN
            RETURN FALSE;
        END IF;
    END LOOP;

    RETURN TRUE;
END;
$$;


