CREATE TABLE "academic_timetable_entries" (
    "id" "uuid" DEFAULT "public"."uuid_generate_v4"() NOT NULL,
    "classroom_course_id" "uuid",
    "day_of_week" character varying(3) NOT NULL,
    "period_id" "uuid" NOT NULL,
    "room_id" "uuid",
    "note" "text",
