--
-- Name: COLUMN "consent_records"."consent_status"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "consent_records"."consent_status" IS 'สถานะ: pending (รอพิจารณา), granted (อนุญาต), denied (ปฏิเสธ), withdrawn (ถอนคืน)';


