--
-- Name: users; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "users" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "national_id" "text",
    "national_id_hash" "text",
    "email" character varying(255),
    "username" character varying(100),
    "password_hash" character varying(255) NOT NULL,
    "title" character varying(50),
    "first_name" character varying(100) NOT NULL,
    "last_name" character varying(100) NOT NULL,
    "nickname" character varying(50),
    "user_type" character varying(50) DEFAULT 'student'::character varying NOT NULL,
    "phone" character varying(20),
    "emergency_contact" character varying(20),
    "line_id" character varying(100),
    "date_of_birth" "date",
    "gender" character varying(20),
    "address" "text",
    "hired_date" "date",
    "resigned_date" "date",
    "status" character varying(50) DEFAULT 'active'::character varying NOT NULL,
    "profile_image_url" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "check_users_status" CHECK ((("status")::"text" = ANY ((ARRAY['active'::character varying, 'inactive'::character varying, 'suspended'::character varying, 'resigned'::character varying])::"text"[]))),
    CONSTRAINT "check_users_user_type" CHECK ((("user_type")::"text" = ANY ((ARRAY['student'::character varying, 'staff'::character varying, 'parent'::character varying])::"text"[]))),
    CONSTRAINT "chk_gender" CHECK (((("gender")::"text" = ANY ((ARRAY['male'::character varying, 'female'::character varying, 'other'::character varying])::"text"[])) OR ("gender" IS NULL))),
    CONSTRAINT "chk_status" CHECK ((("status")::"text" = ANY ((ARRAY['active'::character varying, 'inactive'::character varying, 'suspended'::character varying, 'resigned'::character varying, 'retired'::character varying])::"text"[]))),
    CONSTRAINT "chk_user_type" CHECK ((("user_type")::"text" = ANY ((ARRAY['student'::character varying, 'staff'::character varying, 'parent'::character varying])::"text"[])))
);


--
-- Name: COLUMN "users"."national_id_hash"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "users"."national_id_hash" IS 'Blind index for national ID lookup and uniqueness (HMAC-SHA256 hex; keyed by BLIND_INDEX_KEY).';


--
-- Name: COLUMN "users"."title"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "users"."title" IS 'คำนำหน้า: นาย, นาง, นางสาว, ดร., ศ.ดร.';


--
