--

COMMENT ON COLUMN "users"."hired_date" IS 'วันที่เริ่มงาน (สำหรับ staff)';


--
-- Name: COLUMN "users"."profile_image_url"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "users"."profile_image_url" IS 'Storage path for profile image (e.g., school-xxx/users/profiles/uuid.jpg).
     Will be converted to URL at runtime using configured base URL.';


--
-- Name: COLUMN "users"."metadata"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "users"."metadata" IS 'Free-form per-user metadata. No fixed schema. Normalize keys into columns if they become load-bearing.';


--
-- Name: active_consents; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "active_consents" AS
 SELECT "cr"."id",
    "cr"."user_id",
    "cr"."user_type",
    "cr"."consent_type",
    "cr"."purpose",
    "cr"."data_categories",
    "cr"."consent_status",
    "cr"."granted_at",
    "cr"."withdrawn_at",
    "cr"."expires_at",
    "cr"."consent_method",
    "cr"."ip_address",
    "cr"."user_agent",
    "cr"."consent_text",
    "cr"."consent_version",
    "cr"."is_minor_consent",
    "cr"."parent_guardian_id",
    "cr"."parent_guardian_name",
    "cr"."parent_relationship",
    "cr"."notes",
    "cr"."metadata",
    "cr"."created_at",
    "cr"."updated_at",
    "ct"."name" AS "consent_type_name",
    "ct"."is_required",
    "u"."first_name",
    "u"."last_name",
    "u"."email"
   FROM (("consent_records" "cr"
     JOIN "consent_types" "ct" ON ((("cr"."consent_type")::"text" = ("ct"."code")::"text")))
     JOIN "users" "u" ON (("cr"."user_id" = "u"."id")))
  WHERE ((("cr"."consent_status")::"text" = 'granted'::"text") AND (("cr"."expires_at" IS NULL) OR ("cr"."expires_at" > "now"())));


--
-- Name: VIEW "active_consents"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW "active_consents" IS 'ความยินยอมที่ใช้งานอยู่ (granted และยังไม่หมดอายุ)';


--
-- Name: files; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "files" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid",
    "school_id" character varying(100),
    "filename" character varying(255) NOT NULL,
    "original_filename" character varying(255) NOT NULL,
    "file_size" bigint NOT NULL,
    "mime_type" character varying(100) NOT NULL,
    "storage_path" "text" NOT NULL,
    "file_type" character varying(50) NOT NULL,
    "width" integer,
    "height" integer,
    "has_thumbnail" boolean DEFAULT false,
    "thumbnail_path" "text",
    "is_temporary" boolean DEFAULT false,
    "is_public" boolean DEFAULT false,
    "expires_at" timestamp with time zone,
    "checksum" character varying(64),
    "uploaded_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    CONSTRAINT "chk_file_size_positive" CHECK (("file_size" > 0)),
    CONSTRAINT "chk_file_type_valid" CHECK ((("file_type")::"text" = ANY ((ARRAY['profile_image'::character varying, 'document'::character varying, 'transcript'::character varying, 'certificate'::character varying, 'course_material'::character varying, 'assignment'::character varying, 'school_logo'::character varying, 'school_banner'::character varying, 'id_card'::character varying, 'other'::character varying])::"text"[])))
);


--
-- Name: TABLE "files"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "files" IS 'File metadata for all uploaded files (images, documents, etc.). Uses path-based storage for flexibility with R2/S3.';


--
-- Name: COLUMN "files"."storage_path"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."storage_path" IS 'Relative storage path in R2 bucket (e.g., school-abc/users/profiles/uuid.jpg)';


--
-- Name: COLUMN "files"."file_type"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."file_type" IS 'Classification of file for organizing storage structure';


--
-- Name: COLUMN "files"."is_temporary"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."is_temporary" IS 'Temporary files are automatically cleaned up after expiration';


--
-- Name: COLUMN "files"."is_public"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."is_public" IS 'Public files can be accessed without authentication';


--
-- Name: COLUMN "files"."checksum"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."checksum" IS 'SHA-256 checksum for file integrity verification';


--
-- Name: COLUMN "files"."deleted_at"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "files"."deleted_at" IS 'Soft delete timestamp - files marked for deletion but not yet removed from storage';


--
-- Name: active_files; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "active_files" AS
 SELECT "f"."id",
    "f"."user_id",
    "f"."school_id",
    "f"."filename",
    "f"."original_filename",
    "f"."file_size",
    "f"."mime_type",
    "f"."storage_path",
    "f"."file_type",
    "f"."width",
    "f"."height",
    "f"."has_thumbnail",
    "f"."thumbnail_path",
    "f"."is_temporary",
    "f"."is_public",
    "f"."expires_at",
    "f"."checksum",
    "f"."uploaded_by",
    "f"."created_at",
    "f"."updated_at",
    "f"."deleted_at",
    ((("u"."first_name")::"text" || ' '::"text") || ("u"."last_name")::"text") AS "uploaded_by_name"
   FROM ("files" "f"
     LEFT JOIN "users" "u" ON (("f"."uploaded_by" = "u"."id")))
  WHERE ("f"."deleted_at" IS NULL);


