--

COMMENT ON COLUMN "audit_logs"."entity_type" IS 'Type of entity affected: user, role, organization_unit, grade, etc.';


--
-- Name: COLUMN "audit_logs"."old_values"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "audit_logs"."old_values" IS 'Snapshot of affected row BEFORE the change. Shape mirrors the target table; NULL for create events.';


--
-- Name: COLUMN "audit_logs"."new_values"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "audit_logs"."new_values" IS 'Snapshot of affected row AFTER the change. Shape mirrors the target table; NULL for delete events.';


--
