--

COMMENT ON COLUMN "audit_logs"."changes" IS 'Specific fields that changed (JSON)';


--
-- Name: COLUMN "audit_logs"."metadata"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "audit_logs"."metadata" IS 'Arbitrary context for the audit event (request_id, ip, user_agent, ...). Not a fixed schema; varies per action type.';


