    "credit" double precision DEFAULT 0.0 NOT NULL,
    "hours_per_semester" integer,
    "type" character varying(50) NOT NULL,
    "group_id" "uuid",
    "description" "text",
    "is_active" boolean DEFAULT true,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "start_academic_year_id" "uuid" NOT NULL,
    "term" character varying(20) DEFAULT NULL::character varying,
    "default_instructor_id" "uuid",
    "min_consecutive_periods" integer DEFAULT 1,
    "max_consecutive_periods" integer DEFAULT 2,
    "allow_single_period" boolean DEFAULT true,
    "periods_per_week" integer,
    "allowed_period_ids" "jsonb",
    "allowed_days" "jsonb",
    CONSTRAINT "valid_allowed_days" CHECK ("validate_allowed_days"("allowed_days"))
);


--
-- Name: TABLE "subjects"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "subjects" IS 'รายวิชา (Courses/Subjects)';


--
-- Name: COLUMN "subjects"."type"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."type" IS 'ประเภทวิชา: BASIC, ADDITIONAL, ACTIVITY';


--
-- Name: COLUMN "subjects"."term"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."term" IS 'Recommended semester: 1, 2, Summer, or NULL for Any';


