COMMENT ON COLUMN "subjects"."min_consecutive_periods" IS 'จำนวนคาบต่อเนื่องขั้นต่ำต่อวัน (1=ไม่บังคับ, 2+=ต้องติดกัน)';


--
-- Name: COLUMN "subjects"."max_consecutive_periods"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."max_consecutive_periods" IS 'จำนวนคาบต่อเนื่องสูงสุดต่อวัน';


--
-- Name: COLUMN "subjects"."allow_single_period"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."allow_single_period" IS 'อนุญาตให้มี 1 คาบเดี่ยวได้ไหม (สำหรับคาบที่เหลือ)';


--
-- Name: COLUMN "subjects"."periods_per_week"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."periods_per_week" IS 'จำนวนคาบต่อสัปดาห์ (ใช้สำหรับจัดตาราง)';


--
-- Name: COLUMN "subjects"."allowed_period_ids"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."allowed_period_ids" IS 'Array of period UUIDs that this subject can be scheduled in. NULL = all periods allowed. Example: ["uuid1", "uuid2", "uuid3"]';


--
-- Name: COLUMN "subjects"."allowed_days"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "subjects"."allowed_days" IS 'Array of days (MON,TUE,WED,THU,FRI,SAT,SUN) that this subject can be scheduled. NULL = all days allowed. Example: ["MON", "TUE", "WED"]';


