COMMENT ON TABLE "timetable_entry_instructors" IS 'ครูที่ schedule จริงใน timetable entry (ต่อ entry × ครู)';


--
-- Name: timetable_locked_slots; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "timetable_locked_slots" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "academic_semester_id" "uuid" NOT NULL,
    "scope_type" character varying(20) NOT NULL,
    "scope_ids" "jsonb",
    "subject_id" "uuid" NOT NULL,
    "day_of_week" character varying(3) NOT NULL,
    "period_ids" "jsonb" NOT NULL,
    "room_id" "uuid",
    "instructor_id" "uuid",
    "reason" "text",
    "locked_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "valid_day" CHECK ((("day_of_week")::"text" = ANY ((ARRAY['MON'::character varying, 'TUE'::character varying, 'WED'::character varying, 'THU'::character varying, 'FRI'::character varying, 'SAT'::character varying, 'SUN'::character varying])::"text"[]))),
    CONSTRAINT "valid_scope" CHECK ((("scope_type")::"text" = ANY ((ARRAY['CLASSROOM'::character varying, 'GRADE_LEVEL'::character varying, 'ALL_SCHOOL'::character varying])::"text"[]))),
    CONSTRAINT "valid_scope_ids" CHECK ((((("scope_type")::"text" = 'ALL_SCHOOL'::"text") AND ("scope_ids" IS NULL)) OR ((("scope_type")::"text" <> 'ALL_SCHOOL'::"text") AND ("scope_ids" IS NOT NULL))))
);


--
-- Name: TABLE "timetable_locked_slots"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "timetable_locked_slots" IS 'ช่วงเวลาที่ถูก lock ไว้ล่วงหน้า ห้ามแก้ไข';


--
-- Name: COLUMN "timetable_locked_slots"."scope_type"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_locked_slots"."scope_type" IS 'ขอบเขต: CLASSROOM, GRADE_LEVEL, ALL_SCHOOL';


--
-- Name: COLUMN "timetable_locked_slots"."scope_ids"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_locked_slots"."scope_ids" IS 'IDs ของห้อง/ชั้น (null ถ้า ALL_SCHOOL)';


--
-- Name: COLUMN "timetable_locked_slots"."reason"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_locked_slots"."reason" IS 'เหตุผลที่ lock (เช่น โรงเรียนกำหนด, นโยบาย)';


--
-- Name: timetable_scheduling_jobs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "timetable_scheduling_jobs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "academic_semester_id" "uuid" NOT NULL,
    "classroom_ids" "jsonb" NOT NULL,
    "algorithm" "scheduling_algorithm" DEFAULT 'GREEDY'::"scheduling_algorithm" NOT NULL,
    "config" "jsonb" DEFAULT '{}'::"jsonb",
    "status" "scheduling_status" DEFAULT 'PENDING'::"scheduling_status" NOT NULL,
    "progress" integer DEFAULT 0,
    "quality_score" numeric(5,2),
    "scheduled_courses" integer DEFAULT 0,
    "total_courses" integer DEFAULT 0,
    "failed_courses" "jsonb" DEFAULT '[]'::"jsonb",
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "duration_seconds" integer,
    "error_message" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


--
-- Name: TABLE "timetable_scheduling_jobs"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "timetable_scheduling_jobs" IS 'งานจัดตารางอัตโนมัติ ติดตามสถานะและผลลัพธ์';


--
-- Name: COLUMN "timetable_scheduling_jobs"."classroom_ids"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_scheduling_jobs"."classroom_ids" IS 'รายการห้องเรียนที่ต้องการจัดตาราง';


--
-- Name: COLUMN "timetable_scheduling_jobs"."config"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_scheduling_jobs"."config" IS 'Auto-scheduler run configuration.
Keys (verified used in production):
  - allow_partial: BOOLEAN — accept partial solutions if no full solution found
  - force_overwrite: BOOLEAN — replace existing entries instead of preserving
  - min_quality_score: NUMERIC — reject solutions below this score (0.0-1.0)
  - respect_preferences: BOOLEAN — honor instructor_preferences table
  - timeout_seconds: INTEGER — max compute time before aborting
  - weight_consecutive: NUMERIC — penalty multiplier for non-consecutive periods
  - weight_daily_load: NUMERIC — penalty multiplier for uneven daily distribution
  - weight_distribution: NUMERIC — penalty for clustering same subject
  - weight_instructor_preference: NUMERIC — bonus for matching preferences
  - weight_time_of_day: NUMERIC — bonus for matching time-of-day prefs
Source of truth: scheduler service config (services/scheduler/types.rs).';


--
-- Name: COLUMN "timetable_scheduling_jobs"."quality_score"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_scheduling_jobs"."quality_score" IS 'คะแนนคุณภาพของตาราง (0-100)';


--
-- Name: COLUMN "timetable_scheduling_jobs"."failed_courses"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "timetable_scheduling_jobs"."failed_courses" IS 'รายการวิชาที่จัดไม่สำเร็จ';


