INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('bf21afec-d98c-4e11-91db-ef4fa0b92fcd', 'data_collection_essential', 'การเก็บรวบรวมข้อมูลส่วนบุคคลที่จำเป็น', 'Essential Personal Data Collection', 'การเก็บข้อมูลส่วนบุคคลที่จำเป็นต่อการให้บริการการศึกษา', true, 100, '{student,staff}', 'ข้าพเจ้ายินยอมให้โรงเรียนเก็บรวบรวม ใช้ และเปิดเผยข้อมูลส่วนบุคคลของข้าพเจ้า ได้แก่ ชื่อ-นามสกุล เลขบัตรประชาชน ที่อยู่ หมายเลขโทรศัพท์ และอีเมล เพื่อวัตถุประสงค์ในการจัดการเรียนการสอน การติดต่อสื่อสาร และการปฏิบัติตามกฎหมาย', '1.0', NULL, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');
INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('858e7a5b-5465-48e8-b9bd-c0b0165d6d77', 'student_data_collection', 'การเก็บข้อมูลนักเรียน', 'Student Data Collection', 'การเก็บข้อมูลส่วนบุคคลของนักเรียนเพื่อการจัดการเรียนการสอน', true, 90, '{student}', 'ข้าพเจ้า (ผู้ปกครอง) ยินยอมให้โรงเรียนเก็บรวบรวมข้อมูลส่วนบุคคลของบุตร/ธิดา รวมถึงข้อมูลการเรียน ผลการเรียน การเข้าชั้นเรียน และข้อมูลอื่นๆ ที่เกี่ยวข้องกับการจัดการศึกษา', '1.0', NULL, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');
INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('2e7dbec5-2fef-408c-a177-f97f89d34341', 'medical_data_collection', 'การเก็บข้อมูลสุขภาพ', 'Medical Data Collection', 'การเก็บข้อมูลสุขภาพที่ละเอียดอ่อน เช่น กรุ๊ปเลือด อาการแพ้ โรคประจำตัว', false, 80, '{student,staff}', 'ข้าพเจ้ายินยอมให้โรงเรียนเก็บรวบรวมข้อมูลสุขภาพของข้าพเจ้า/บุตร-ธิดา ได้แก่ กรุ๊ปเลือด อาการแพ้ยา/อาหาร โรคประจำตัว เพื่อวัตถุประสงค์ในการดูแลสุขภาพและความปลอดภัย', '1.0', NULL, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');
INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('d50f3e82-3037-4592-9939-ce6dda248022', 'communication_consent', 'การติดต่อสื่อสารและการแจ้งข่าวสาร', 'Communication Consent', 'การส่งข่าวสาร ประกาศ และกิจกรรมของโรงเรียน', false, 50, '{student,staff,parent}', 'ข้าพเจ้ายินยอมให้โรงเรียนติดต่อสื่อสารกับข้าพเจ้าเพื่อแจ้งข่าวสาร ประกาศ กิจกรรม และข้อมูลที่เกี่ยวข้องกับการจัดการศึกษา ผ่านทางอีเมล โทรศัพท์ หรือ LINE', '1.0', 365, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');
INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('b003e621-c4c2-40fc-9bee-93c60d2680f5', 'media_publication_consent', 'การเผยแพร่ภาพและผลงาน', 'Media Publication Consent', 'การเผยแพร่ภาพถ่าย วิดีโอ และผลงานของนักเรียนผ่านช่องทางต่างๆ', false, 40, '{student}', 'ข้าพเจ้า (ผู้ปกครอง) ยินยอมให้โรงเรียนถ่ายภาพ/วิดีโอ และเผยแพร่ภาพ ผลงาน และกิจกรรมของบุตร/ธิดา ผ่านเว็บไซต์โรงเรียน Facebook Line หรือช่องทางสื่อสารอื่นๆ ของโรงเรียน', '1.0', 365, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');
INSERT INTO "consent_types" ("id", "code", "name", "name_en", "description", "is_required", "priority", "applicable_user_types", "consent_text_template", "consent_version", "default_duration_days", "is_active", "created_at", "updated_at") VALUES ('68c9b4b9-e3a1-477a-b907-5dc3a7e797b3', 'third_party_sharing', 'การแบ่งปันข้อมูลกับบุคคลที่สาม', 'Third Party Data Sharing', 'การแบ่งปันข้อมูลกับหน่วยงานภายนอก เช่น สพฐ. กระทรวงศึกษาธิการ', false, 60, '{student,staff}', 'ข้าพเจ้ายินยอมให้โรงเรียนเปิดเผยข้อมูลส่วนบุคคลของข้าพเจ้าให้แก่หน่วยงานราชการที่เกี่ยวข้อง (เช่น สพฐ. กระทรวงศึกษาธิการ) เพื่อวัตถุประสงค์ในการรายงานและปฏิบัติตามกฎหมาย', '1.0', NULL, true, '2026-06-07 17:07:13.459988+00', '2026-06-07 17:07:13.459988+00');


